#include <bits/stdc++.h>
using namespace std;;

int n, m, c[500005];

int lowbit(int x)
{
    return x & -x;
}

void add(int x, int k)
{
    for(; x <= n; x += lowbit(x))
        c[x] += k;
}

int getsum(int x)
{
    int sum = 0;
    for(; x; x -= lowbit(x))
        sum += c[x];
    return sum;
}

int main()
{
    cin >> n >> m;
    for(int i = 1; i <= n; i++)
    {
        int x;
        cin >> x;
        add(i, x);
    }
    for(int i = 1; i <= m; i++)
    {
        int op, x, y;
        cin >> op >> x >> y;
        if(op == 1) 
            add(x, y);
        else
            cout << getsum(y) - getsum(x - 1) << endl;
    }
}
